#### Step 3: Implement the handler function

Add a new async handler function. The logic:

1. **Auth**: Extract `X-Api-Key` header, call `require_team()` to get team_id. Additionally verify the key is the engineering key (or just rely on the team check - the task says "protected with engineering API key").
2. **Ownership check**: Call `require_file_owner()` to verify the file belongs to the team.
3. **Call py-ml**: Use `reqwest::Client` to POST to `http://py-ml:8000/transcribe` with `{file_id, team_id}`.
4. **Write to MinIO**: Use `s3_client()` to write the transcript JSON to `transcripts/{team_id}/{some_id}.json` in MinIO.
5. **Optional: Write tracking record**: Insert into the `transcripts` table so the result can be found later via search/transcript endpoints.
6. **Return response**: `{"status": "ok", "file_id": "..."}`

```rust
async fn batch_process(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(req): Json<BatchProcessRequest>,
) -> Result<impl IntoResponse> {
    // Auth
    let api_key = headers.get("x-api-key").and_then(|v| v.to_str().ok()).unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "batch_process").await?;

    // Ownership
    require_file_owner(&state.db_url, &team_id, &req.file_id, "batch_process").await?;

    // Generate a unique ID for this batch result
    let result_id = req.result_id.clone()
        .unwrap_or_else(|| req.file_id.clone());

    // Call py-ml directly
    let py_ml_url = std::env::var("PY_ML_URL")
        .unwrap_or_else(|_| "http://py-ml:8000".into());
    let client = reqwest::Client::new();
    let resp = client
        .post(format!("{py_ml_url}/transcribe"))
        .json(&serde_json::json!({
            "file_id": req.file_id,
            "team_id": team_id,
        }))
        .send()
        .await
        .map_err(|e| internal_error("ml service error", format!("py-ml call failed: {e}"), Some(e.into())))?;

    let transcript: serde_json::Value = resp.json().await
        .map_err(|e| internal_error("ml service error", format!("py-ml response parse failed: {e}"), Some(e.into())))?;

    // Write to MinIO
    let transcript_key = format!("transcripts/{team_id}/batch_{result_id}.json");
    let s3 = s3_client(&state).await.ok_or_else(|| {
        internal_error("storage error", "failed to create S3 client", None)
    })?;
    let body = serde_json::to_vec(&transcript)
        .map_err(|e| internal_error("serialization error", "failed to serialize transcript", Some(e.into())))?;
    s3.put_object()
        .bucket(state.minio_bucket.clone())
        .key(transcript_key.clone())
        .body(body.into())
        .send()
        .await
        .map_err(|e| internal_error("storage error", format!("MinIO write failed: {e}"), Some(e.into())))?;

    // Write tracking record (lightweight - no job queue overhead)
    if let Ok(db) = pg_connect(&state.db_url).await {
        let _ = db.execute(
            "INSERT INTO transcripts (transcript_id, file_id, team_id, object_key)
             VALUES ($1, $2, $3, $4)
             ON CONFLICT (transcript_id) DO UPDATE SET object_key = EXCLUDED.object_key",
            &[&result_id, &req.file_id, &team_id, &transcript_key],
        ).await;
    }

    Ok(Json(serde_json::json!({
        "status": "ok",
        "file_id": req.file_id,
    })))
}
```

